// Simple MongoDB Atlas Data API helper for the frontend
// WARNING: Calling your database directly from client-side code exposes keys/credentials to users.
// Recommended: use a backend proxy or serverless function. This file exists for quick testing only.

const config = {
  // Example values — replace with your Atlas Data API info
  // apiUrl: 'https://data.mongodb-api.com/app/<APP-ID>/endpoint/data/v1',
  // apiKey: '<YOUR_DATA_API_KEY>',
  // dataSource: 'Cluster0',
  // database: 'your_database_name',
  apiUrl: '',
  apiKey: '',
  dataSource: '',
  database: '',
  // Optional raw MongoDB connection URI (e.g. mongodb+srv://...)
  // NOTE: Placing this URI in client-side code will expose credentials publicly
  // and browsers cannot connect to MongoDB via the native driver. This value
  // is stored here because you requested it, but it's only suitable for
  // server-side Node usage or for quick local testing behind a secure proxy.
  mongoUri: '',
};

export function setMongoConfig(userConfig = {}) {
  Object.assign(config, userConfig);
}

async function callDataApi(action, body) {
  if (!config.apiUrl || !config.apiKey) {
    throw new Error('MongoDB Data API not configured. Set apiUrl and apiKey via setMongoConfig().');
  }

  const url = `${config.apiUrl}/${action}`.replace(/\/+/g, '/');

  const res = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'api-key': config.apiKey,
    },
    body: JSON.stringify(body),
  });

  const json = await res.json();
  if (!res.ok) {
    const err = json?.error || json;
    throw new Error('Atlas Data API error: ' + JSON.stringify(err));
  }
  return json;
}

// Generic find helper
export async function findDocuments(collection, filter = {}, projection = null, limit = 100) {
  const body = {
    dataSource: config.dataSource,
    database: config.database,
    collection,
    filter,
    limit,
  };
  if (projection) body.projection = projection;

  const result = await callDataApi('action/find', body);
  return result.documents || [];
}

// Convenience: get market documents — only return docs where `prediction` exists and is not 'down'
export async function getMarketDocuments(opts = {}) {
  const { collectionName = 'stocks', limit = 500 } = opts;
  // filter: prediction exists and not null, and not 'down'
  const filter = { prediction: { $ne: null, $exists: true, $nin: ['down'] } };
  const docs = await findDocuments(collectionName, filter, null, limit);
  return docs;
}

// Convenience: get news documents — only return where prediction exists (and not 'down')
export async function getNewsDocuments(opts = {}) {
  const { collectionName = 'news', limit = 500 } = opts;
  const filter = { prediction: { $ne: null, $exists: true, $nin: ['down'] } };
  const docs = await findDocuments(collectionName, filter, null, limit);
  return docs;
}

// Expose current config for debugging
export function getConfig() {
  return { ...config };
}

export default {
  setMongoConfig,
  getMarketDocuments,
  getNewsDocuments,
  getConfig,
};
